#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MAX_LINE 256
#define MAX_WORDS 30

/* Trim leading and trailing spaces in place */
void trim(char *s) {
    int i, start = 0, end = strlen(s) - 1;
    while (start < (int)strlen(s) && isspace((unsigned char)s[start])) start++;
    while (end >= start && isspace((unsigned char)s[end])) end--;
    for (i = start; i <= end; ++i) s[i - start] = s[i];
    s[i - start] = '\0';
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[MAX_LINE];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "
")] = '\0';
        trim(line);
        char *token = strtok(line, " ");
        char *words[MAX_WORDS];
        int cnt = 0;
        while (token && cnt < MAX_WORDS) {
            words[cnt++] = token;
            token = strtok(NULL, " ");
        }
        int unique = 0;
        for (int i = 0; i < cnt; ++i) {
            int seen = 0;
            for (int j = 0; j < i; ++j) {
                if (strcmp(words[i], words[j]) == 0) { seen = 1; break; }
            }
            if (!seen) unique++;
        }
        printf("%d
", unique);
    }
    return 0;
}

