#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        line = data[i] if i < len(data) else ''
        cleaned = line.strip()
        if not cleaned:
            out.append('0')
            continue
        words = cleaned.split()
        out.append(str(len(set(words))))
    sys.stdout.write('
'.join(out))

if __name__ == "__main__":
    main()

